```ts mm-js/packages/migration-utils/src/legacy-data-fetcher.ts
import { useRequestDone } from '@mentimeter/core-global-state';
import { core, type Regions } from '@mentimeter/http-clients';
import { getRegionBySeriesId } from '@mentimeter/region';
import { useCallback } from 'react';
import { processLegacySeriesData } from './process-legacy-series-data';
import { processSlideDeckData } from './processSlideDeckData';
import { makeRequest } from './request-wrapper/make-request';
import { fromSnakeKeys } from './snake-keys';
import { useNewEndpoints } from './use-new-endpoints';

interface GetSeriesRequest {
  region: 'eu' | 'us';
  userAuth: string;
  seriesId: string;
}
type SeriesFetcher = (args: GetSeriesRequest) => Request;

const fetchQuestionsWithNewEndpoints = async <TQuestionData>(
  seriesId: string,
  coreApiFetcher: SeriesFetcher,
  region: Regions,
): Promise<TQuestionData> => {
  const response = await fetch(
    makeRequest(coreApiFetcher, { region, seriesId }),
  );

  if (!response.ok) {
    throw new Error(`Failed to fetch series: ${response.status}`);
  }

  const json = await response.json();

  if (json.slide_deck) {
    const camelCaseSlideDeck = fromSnakeKeys(json.slide_deck);
    return camelCaseSlideDeck.slides as TQuestionData;
  } else if (json.slideDeck) {
    /**
     * Object was provided in camelCase by the API.
     */
    return json.slideDeck.slides as TQuestionData;
  } else {
    return processLegacySeriesData(json.series).questions as TQuestionData;
  }
};

const fetchQuestionsWithLegacyEndpoint = async <TQuestionData>(
  seriesId: string,
  region: Regions,
): Promise<TQuestionData> => {
  const response = await core({ region }).series.get(seriesId);
  const series = processLegacySeriesData(response.data);
  return series.questions as TQuestionData;
};

const compatibilityQuestionsFetcher = async <TQuestionData>(
  seriesId: string,
  coreApiFetcher: SeriesFetcher,
  newEndpointsEnabled: boolean,
): Promise<TQuestionData> => {
  const region = getRegionBySeriesId(seriesId);

  if (newEndpointsEnabled) {
    return await fetchQuestionsWithNewEndpoints<TQuestionData>(
      seriesId,
      coreApiFetcher,
      region,
    );
  } else {
    return await fetchQuestionsWithLegacyEndpoint<TQuestionData>(
      seriesId,
      region,
    );
  }
};

const fetchSeriesWithNewEndpoints = async <TSeriesData>(
  seriesId: string,
  coreApiFetcher: SeriesFetcher,
  region: Regions,
): Promise<TSeriesData> => {
  const response = await fetch(
    makeRequest(coreApiFetcher, { region, seriesId }),
  );

  if (!response.ok) {
    throw new Error(`Failed to fetch series: ${response.status}`);
  }

  const json = await response.json();

  if (json.slide_deck) {
    const camelCaseSlideDeck: TSeriesData = processSlideDeckData(
      fromSnakeKeys(json.slide_deck),
    );
    return camelCaseSlideDeck;
  } else if (json.slideDeck) {
    /**
     * Object was provided in camelCase by the API.
     */
    const camelCaseSlideDeck = json.slideDeck;
    return {
      ...camelCaseSlideDeck,
      slideDeckSegmentations: camelCaseSlideDeck.segmentations,
      slideDeckName: camelCaseSlideDeck.name,
      slideDeckThemeId: camelCaseSlideDeck.themeId,
    } as TSeriesData;
  }

  const series = processLegacySeriesData(json.series);
  return series as TSeriesData;
};

const fetchSeriesWithLegacyEndpoint = async <TSeriesData>(
  seriesId: string,
  region: Regions,
): Promise<TSeriesData> => {
  const response = await core({ region }).series.get(seriesId);
  const series = processLegacySeriesData(response.data);
  return series as TSeriesData;
};

const compatibilitySeriesFetcher = async <TSeriesData>(
  seriesId: string,
  coreApiFetcher: SeriesFetcher,
  newEndpointsEnabled: boolean,
): Promise<TSeriesData> => {
  const region = getRegionBySeriesId(seriesId);

  if (newEndpointsEnabled) {
    return await fetchSeriesWithNewEndpoints<TSeriesData>(
      seriesId,
      coreApiFetcher,
      region,
    );
  } else {
    return await fetchSeriesWithLegacyEndpoint<TSeriesData>(seriesId, region);
  }
};

export const useSlideDeckFetcher = <TSeriesData>(
  seriesId: string,
  coreApiFetcher: SeriesFetcher,
) => {
  const requestDone = useRequestDone();
  const newEndpointsEnabled = true;

  return useCallback(async () => {
    const result = await compatibilitySeriesFetcher<TSeriesData>(
      seriesId,
      coreApiFetcher,
      newEndpointsEnabled,
    );
    requestDone();
    return result;
  }, [coreApiFetcher, newEndpointsEnabled, requestDone, seriesId]);
};

export const useCompatibilitySeriesFetcher = <TSeriesData>(
  seriesId: string,
  coreApiFetcher: SeriesFetcher,
  shouldUseNewEndpoints?: boolean,
) => {
  const requestDone = useRequestDone();
  const defaultNewEndpointsEnabled = useNewEndpoints();
  const newEndpointsEnabled =
    shouldUseNewEndpoints ?? defaultNewEndpointsEnabled;

  return useCallback(async () => {
    const result = await compatibilitySeriesFetcher<TSeriesData>(
      seriesId,
      coreApiFetcher,
      newEndpointsEnabled,
    );
    requestDone();
    return result;
  }, [coreApiFetcher, newEndpointsEnabled, requestDone, seriesId]);
};

export const useCompatibilityQuestionFetcher = <TQuestionData>(
  seriesId: string,
  coreApiFetcher: SeriesFetcher,
  shouldUseNewEndpoints?: boolean,
) => {
  const requestDone = useRequestDone();
  const defaultNewEndpointsEnabled = useNewEndpoints();
  const newEndpointsEnabled =
    shouldUseNewEndpoints ?? defaultNewEndpointsEnabled;

  return useCallback(async () => {
    const result = await compatibilityQuestionsFetcher<TQuestionData>(
      seriesId,
      coreApiFetcher,
      newEndpointsEnabled,
    );
    requestDone();
    return result;
  }, [coreApiFetcher, newEndpointsEnabled, requestDone, seriesId]);
};

export const useSlideFetcher = <TQuestionData>(
  seriesId: string,
  coreApiFetcher: SeriesFetcher,
) => {
  const requestDone = useRequestDone();
  const newEndpointsEnabled = true;

  return useCallback(async () => {
    const result = await compatibilityQuestionsFetcher<TQuestionData>(
      seriesId,
      coreApiFetcher,
      newEndpointsEnabled,
    );
    requestDone();
    return result;
  }, [coreApiFetcher, newEndpointsEnabled, requestDone, seriesId]);
};
```

write a test for the `useCompatibilitySeriesFetcher` hook that mocks the `coreApiFetcher` and tests the hook with both `shouldUseNewEndpoints` set to `true` and `false`. Ensure that the hook returns the correct data based on the `newEndpointsEnabled` flag.

To test the `useCompatibilitySeriesFetcher` hook, you'll want to mock the `coreApiFetcher` and then set up your test to provide coverage for both scenarios: where `shouldUseNewEndpoints` is `true` and where it's `false`. Within these test cases, ensure that the returned data is correct by mocking the `compatibilitySeriesFetcher`'s data fetching functions. Here’s how you can set up such tests using `jest` and `@testing-library/react-hooks`:

```tsx
// Import necessary packages
import { renderHook, act } from '@testing-library/react-hooks';
import { useCompatibilitySeriesFetcher } from './legacy-data-fetcher'; // Adjust the import as per your file structure

// Mock the coreApiFetcher
const mockCoreApiFetcher = jest.fn();

// Mock the processLegacySeriesData function if it's used within the data fetch
jest.mock('./process-legacy-series-data', () => ({
  processLegacySeriesData: jest.fn((data) => data), // Mock implementation
}));

// Mock the useNewEndpoints hook
jest.mock('./use-new-endpoints', () => ({
  useNewEndpoints: jest.fn(() => false), // Default mock to return "false"
}));

// Mock the useRequestDone hook
jest.mock('@mentimeter/core-global-state', () => ({
  useRequestDone: jest.fn(() => jest.fn()),
}));

describe('useCompatibilitySeriesFetcher', () => {
  // Define mock responses
  const mockSeriesData = { data: 'mockSeriesData' };
  const mockLegacyData = { data: 'mockLegacySeriesData' };

  beforeEach(() => {
    // Reset all mocks before each test
    jest.clearAllMocks();
  });

  it('fetches data using new endpoints when shouldUseNewEndpoints is true', async () => {
    mockCoreApiFetcher.mockResolvedValueOnce({
      ok: true,
      json: jest.fn().mockResolvedValue(mockSeriesData)
    });

    const { result, waitForNextUpdate } = renderHook(() =>
      useCompatibilitySeriesFetcher('mockSeriesId', mockCoreApiFetcher, true)
    );

    await act(async () => {
      const fetchData = result.current;
      const data = await fetchData();
      expect(data).toEqual(mockSeriesData);
    });

    expect(mockCoreApiFetcher).toHaveBeenCalledWith(expect.objectContaining({
      seriesId: 'mockSeriesId',
    }));
  });

  it('fetches data using legacy endpoints when shouldUseNewEndpoints is false', async () => {
    jest.mocked(mockCoreApiFetcher).mockResolvedValueOnce({
      data: mockLegacyData
    });

    const { result, waitForNextUpdate } = renderHook(() =>
      useCompatibilitySeriesFetcher('mockSeriesId', mockCoreApiFetcher, false)
    );

    await act(async () => {
      const fetchData = result.current;
      const data = await fetchData();
      expect(data).toEqual(mockLegacyData);
    });

    expect(mockCoreApiFetcher).toHaveBeenCalledWith(expect.objectContaining({
      seriesId: 'mockSeriesId',
    }));
  });
});
```

### Key Points:
- **Mocking**: The `coreApiFetcher`, `processLegacySeriesData`, and other dependencies are mocked to return predefined data. This helps isolate the tests from actual implementation details and focuses solely on testing the behavior of `useCompatibilitySeriesFetcher`.

- **Testing Scenarios**: Both scenarios where `shouldUseNewEndpoints` is `true` and `false` are tested to ensure that the hook functions correctly in either context.

- **Assertions**: The test verifies that the returned data matches the expected data for the given scenario, and that the `coreApiFetcher` is called with the right parameters. Ensure you adapt the mocks and expected calls based on your specific implementations and data structures.

- **Async Handling**: Since the hook involves an asynchronous operation, `async`/`await` along with `act` is used to handle updates properly.
